// ── Node 3: game_pk 배열 파싱 + 오늘 날짜 필터링 ──────────────────────────
const data  = $input.first().json;
const today = $now.format('YYYY-MM-DD');
const games = [];

for (const dateEntry of (data.dates || [])) {
  // 오늘 날짜만 처리
  if (dateEntry.date !== today) continue;

  for (const game of (dateEntry.games || [])) {
    // 이미 종료된 경기 스킵
    if (game.status?.abstractGameState === 'Final') continue;

    games.push({
      game_pk:         game.gamePk,
      game_date:       dateEntry.date,
      game_datetime:   game.gameDate,
      home_team_id:    game.teams?.home?.team?.id,
      home_team:       game.teams?.home?.team?.name,
      away_team_id:    game.teams?.away?.team?.id,
      away_team:       game.teams?.away?.team?.name,
      status:          game.status?.detailedState,
      home_pitcher_id: game.teams?.home?.probablePitcher?.id ?? null,
      away_pitcher_id: game.teams?.away?.probablePitcher?.id ?? null
    });
  }
}

if (games.length === 0) {
  // 경기 없을 때 빈 결과로 워크플로우 종료
  return [{ json: { skipped: true, reason: '오늘 예정 경기 없음', date: today } }];
}

// 경기별 아이템 분기 → 이후 노드가 경기 수만큼 루프 실행
return games.map(g => ({ json: g }));

// ── Node 5: pitcher_id · catcher_id · fielder_ids 추출 ───────────────────────
// 양방향 플레이어(투수이자 타자, 예: 오타니) 예외 처리 포함
const boxscore = $input.first().json;
const gameInfo = $('game_pk 파싱').item.json; // 페어링된 상위 아이템

const result = [];

for (const side of ['home', 'away']) {
  const team = boxscore.teams?.[side];
  if (!team) continue;

  const pitcherIds        = team.pitchers || [];
  const startingPitcherId = pitcherIds[0] ?? null;
  if (!startingPitcherId) continue; // 선발 투수 미확정 시 스킵

  let   catcherId   = null;
  const fielderIds  = [];
  let   isTwoWay    = false;

  for (const playerId of (team.battingOrder || [])) {
    const player  = team.players?.[`ID${playerId}`];
    const posCode = player?.position?.code;

    // 포수(position 2) 추출
    if (posCode === '2') catcherId = playerId;

    // 양방향 플레이어 감지: 타선에 포함된 투수
    if (posCode === '1' && pitcherIds.includes(playerId)) isTwoWay = true;

    // 야수 포지션(3~9) 추출
    const posNum = parseInt(posCode);
    if (posNum >= 3 && posNum <= 9) {
      fielderIds.push({ fielder_id: playerId, position: posNum });
    }
  }

  // 상대 타선 좌/우타 분포 집계 (AI matchup 분석용)
  const oppSide   = side === 'home' ? 'away' : 'home';
  const oppTeam   = boxscore.teams?.[oppSide];
  const oppBatters = [];
  for (const playerId of (oppTeam?.battingOrder || [])) {
    const player = oppTeam?.players?.[`ID${playerId}`];
    oppBatters.push({
      batter_id:   playerId,
      batter_name: player?.person?.fullName,
      bat_side:    player?.batSide?.code,
      position:    player?.position?.abbreviation
    });
  }

  result.push({
    json: {
      game_pk:          gameInfo.game_pk,
      game_date:        gameInfo.game_date,
      pitcher_id:       startingPitcherId,
      pitcher_side:     side,
      catcher_id:       catcherId,
      fielder_ids:      fielderIds,
      is_two_way:       isTwoWay,
      opp_batters:      oppBatters,
      opp_left_count:   oppBatters.filter(b => b.bat_side === 'L').length,
      opp_right_count:  oppBatters.filter(b => b.bat_side === 'R').length
    }
  });
}

return result;

